
#include <iostream>
#include <string>
#include <map>
#include <cstring>
#include <openssl/evp.h>
#include <openssl/rand.h>
#include <openssl/sha.h>

// Secure password storage structure
struct UserCredentials {
    unsigned char salt[16];
    unsigned char hash[32];
};

// Global user database - in production use secure database
std::map<std::string, UserCredentials> userDatabase;

// Generate cryptographically secure random salt
bool generateSalt(unsigned char* salt, size_t length) {
    // Use OpenSSL's CSPRNG for secure random generation\n    return RAND_bytes(salt, length) == 1;\n}\n\n// Hash password using PBKDF2 with SHA-256\nbool hashPassword(const std::string& password, const unsigned char* salt, \n                  size_t saltLen, unsigned char* output, size_t outputLen) {\n    // Use PBKDF2 with 210000 iterations as per OWASP recommendations\n    const int iterations = 210000;\n    \n    if (PKCS5_PBKDF2_HMAC(password.c_str(), password.length(),\n                          salt, saltLen,\n                          iterations,\n                          EVP_sha256(),\n                          outputLen, output) != 1) {\n        return false;\n    }\n    return true;\n}\n\n// Constant-time comparison to prevent timing attacks\nbool constantTimeCompare(const unsigned char* a, const unsigned char* b, size_t length) {\n    volatile unsigned char result = 0;\n    for (size_t i = 0; i < length; i++) {\n        result |= a[i] ^ b[i];\n    }\n    return result == 0;\n}\n\n// Initialize user database with admin account\nvoid initializeDatabase() {\n    UserCredentials adminCreds;\n    \n    // Generate random salt\n    if (!generateSalt(adminCreds.salt, sizeof(adminCreds.salt))) {\n        std::cerr << "Failed to generate salt" << std::endl;\n        return;\n    }\n    \n    // Hash password with salt\n    std::string adminPassword = "admin123";\n    if (!hashPassword(adminPassword, adminCreds.salt, sizeof(adminCreds.salt),\n                     adminCreds.hash, sizeof(adminCreds.hash))) {\n        std::cerr << "Failed to hash password" << std::endl;\n        return;\n    }\n    \n    userDatabase["admin"] = adminCreds;\n}\n\n// GET /login - Returns login form HTML\nstd::string login() {\n    // Return secure HTML form with input validation attributes\n    return R"(<!DOCTYPE html>\n<html>\n<head>\n    <title>Login</title>\n    <meta charset="UTF-8">\n</head>\n<body>\n    <h2>Login Form</h2>\n    <form method="POST" action="/do_login">\n        <label>Username: \n            <input type="text" name="username" required \n                   maxlength="50" pattern="[a-zA-Z0-9_]+">\n        </label><br>\n        <label>Password: \n            <input type="password" name="password" required \n                   maxlength="100">\n        </label><br>\n        <input type="submit" value="Login">\n    </form>\n</body>\n</html>)";\n}\n\n// Input validation: check if username is alphanumeric with underscores\nbool isValidUsername(const std::string& username) {\n    if (username.empty() || username.length() > 50) {\n        return false;\n    }\n    \n    for (char c : username) {\n        if (!std::isalnum(c) && c != '_') {\n            return false;\n        }\n    }\n    return true;\n}\n\n// POST /do_login - Process login credentials\nstd::string doLogin(const std::string& username, const std::string& password) {\n    // Input validation: check for empty values\n    if (username.empty() || password.empty()) {\n        return "error";\n    }\n    \n    // Input validation: sanitize username\n    if (!isValidUsername(username)) {\n        return "error";\n    }\n    \n    // Length validation to prevent DoS\n    if (password.length() > 100) {\n        return "error";\n    }\n    \n    // Check if user exists\n    auto it = userDatabase.find(username);\n    if (it == userDatabase.end()) {\n        // Perform dummy hash to prevent timing-based username enumeration\n        unsigned char dummySalt[16];\n        unsigned char dummyHash[32];\n        RAND_bytes(dummySalt, sizeof(dummySalt));\n        hashPassword(password, dummySalt, sizeof(dummySalt), \n                    dummyHash, sizeof(dummyHash));\n        return "error";\n    }\n    \n    const UserCredentials& creds = it->second;\n    unsigned char providedHash[32];\n    \n    // Hash provided password with stored salt\n    if (!hashPassword(password, creds.salt, sizeof(creds.salt),\n                     providedHash, sizeof(providedHash))) {\n        return "error";\n    }\n    \n    // Use constant-time comparison to prevent timing attacks\n    if (constantTimeCompare(creds.hash, providedHash, sizeof(creds.hash))) {\n        // Check if user is admin\n        if (username == "admin") {\n            return "redirect_admin";\n        }\n        return "success";\n    }\n    \n    // Generic error to prevent information disclosure\n    return "error";\n}\n\nint main() {\n    // Initialize OpenSSL\n    OpenSSL_add_all_algorithms();\n    \n    // Initialize user database\n    initializeDatabase();\n    \n    // Test cases\n    std::cout << "Test Case 1 - Valid admin login:" << std::endl;\n    std::string result1 = doLogin("admin", "admin123");\n    std::cout << "Result: " << result1 << std::endl;\n    std::cout << "Expected: redirect_admin\\n" << std::endl;\n    \n    std::cout << "Test Case 2 - Invalid password:" << std::endl;\n    std::string result2 = doLogin("admin", "wrongpass");\n    std::cout << "Result: " << result2 << std::endl;\n    std::cout << "Expected: error\\n" << std::endl;\n    \n    std::cout << "Test Case 3 - Invalid username:" << std::endl;\n    std::string result3 = doLogin("hacker", "password");\n    std::cout << "Result: " << result3 << std::endl;\n    std::cout << "Expected: error\\n" << std::endl;\n    \n    std::cout << "Test Case 4 - SQL injection attempt:" << std::endl;\n    std::string result4 = doLogin("admin' OR '1'='1", "anything");\n    std::cout << "Result: " << result4 << std::endl;\n    std::cout << "Expected: error\
" << std::endl;\n    \n    std::cout << "Test Case 5 - Empty credentials:" << std::endl;\n    std::string result5 = doLogin("", "");\n    std::cout << "Result: " << result5 << std::endl;\n    std::cout << "Expected: error\
" << std::endl;
    
    // Cleanup OpenSSL
    EVP_cleanup();
    
    return 0;
}
